/**
 * Retro-Clobber Guard — centralized skip-manual logic for retrospectives writes.
 * SD-LEO-INFRA-BACKEND-WRITE-SAFETY-001 (formerly SD-FDBK-INFRA-HANDOFF-RETRO-GENERATORS-001, cancelled)
 *
 * All handoff retro-writers (9+ wire-in sites) consult `isSafeToWriteRetro`
 * before INSERT/UPDATE on the `retrospectives` table to prevent overwriting
 * manually-curated content with auto-generated boilerplate.
 *
 * Source incident: retro `84ada45e-3b5b-460b-a1a3-385732a3895f` for
 * SD-FDBK-INFRA-LAYER-SIDE-CLAIMING-001 went 10/4/5 → 1/1/1, score 70 → 60 → 10
 * (cost 2/3 bypass quota). The retro had `generated_by=null` and
 * `auto_generated=false`, but the existing enricher's check at
 * `retrospective-enricher.js:464` (`if (retro.generated_by && !auto.includes(...))`)
 * treats `null` as falsy and falls through to overwrite. This helper handles
 * the null-with-rich-content case explicitly (`manual_retro_null_inferred`).
 *
 * Sibling pattern: scripts/modules/handoff/lib/branch-file-reader.js (ESM,
 * named exports + JSDoc style).
 *
 * Static guard test: lib/eva/__tests__/retro-clobber-guard.test.js enumerates
 * all wire-in sites and fails the suite if any forgets to consult this helper.
 */

/**
 * EXPORTED whitelist of `generated_by` values that mark a retro as auto-generated.
 * Sites consume this constant — they MUST NOT re-hardcode the list (sibling-parity
 * rule; static guard test asserts no re-hardcoding outside this file).
 */
export const AUTO_GENERATED_TYPES = [
  'AUTO',
  'AUTO_HOOK',
  'NON_SD_MERGE',
  'RETRO_SUB_AGENT',
  'SUB_AGENT',
  'system',
  'non_interactive',
];

const RICH_THRESHOLD_AVG_LEN = parseInt(process.env.LEO_RETRO_GUARD_RICH_THRESHOLD_AVG_LEN || '100', 10);
const RICH_THRESHOLD_COUNT = parseInt(process.env.LEO_RETRO_GUARD_RICH_THRESHOLD_COUNT || '3', 10);

/**
 * Determine if `key_learnings` array contains rich (manually-curated quality) content.
 * Threshold: >= RICH_THRESHOLD_COUNT entries with average length > RICH_THRESHOLD_AVG_LEN chars.
 *
 * @param {*} keyLearnings - the key_learnings field from a retrospectives row
 * @returns {boolean}
 */
export function hasRichContent(keyLearnings) {
  if (!Array.isArray(keyLearnings)) return false;
  if (keyLearnings.length < RICH_THRESHOLD_COUNT) return false;
  const totalLen = keyLearnings.reduce((sum, l) => {
    // SD-FDBK-FIX-PREVENT-AUTOMATED-RETRO-001: also read the production `lesson` key —
    // SD_COMPLETION key_learnings are shaped {lesson:...}; without this they scored as
    // empty (length 0) and rich completion retros were mis-classified `auto_thin`.
    const text = typeof l === 'string' ? l : (l?.learning || l?.text || l?.lesson || '');
    return sum + text.length;
  }, 0);
  const avgLen = totalLen / keyLearnings.length;
  return avgLen > RICH_THRESHOLD_AVG_LEN;
}

/**
 * Classify a retrospectives row by skip-decision rules.
 *
 * Reasons:
 *   - no_retro:                    no row exists for sdId (safe to INSERT)
 *   - published_sd_completion:     existing row is a PUBLISHED or high-quality (>=70) SD_COMPLETION retro (skip — never clobber a finished retrospective)
 *   - manual_retro:                generated_by is set AND not in AUTO_GENERATED_TYPES (skip)
 *   - manual_retro_null_inferred:  generated_by is null AND content is rich (skip — primary leak case)
 *   - rich_existing_content:       generated_by is auto BUT content is rich (skip)
 *   - auto_thin:                   generated_by is auto AND content is thin (safe to overwrite)
 *
 * @param {Object|null} retro - the existing retrospectives row, or null if none
 * @returns {{safe: boolean, reason: string}}
 */
export function classifyRetro(retro) {
  if (!retro) return { safe: true, reason: 'no_retro' };

  // SD-FDBK-FIX-PREVENT-AUTOMATED-RETRO-001: a PUBLISHED or high-quality SD_COMPLETION
  // retrospective is authoritative and must NEVER be auto-overwritten — not even by an
  // "auto-generated" writer. Real completion retros are created with
  // generated_by='SUB_AGENT' (in AUTO_GENERATED_TYPES) and key_learnings shaped {lesson},
  // so the generated_by/richness branches below otherwise green-light a clobber
  // (RCA fc3f0c84: 116 rows exposed; witnessed 100→stub on row a311f9a1). Decide on the
  // authoritative columns, not content inference. Checked FIRST so it always wins.
  if (retro.retro_type === 'SD_COMPLETION' &&
      (retro.status === 'PUBLISHED' || (retro.quality_score ?? 0) >= 70)) {
    return { safe: false, reason: 'published_sd_completion' };
  }

  const isAutoGenerated = retro.generated_by && AUTO_GENERATED_TYPES.includes(retro.generated_by);
  const rich = hasRichContent(retro.key_learnings);

  if (retro.generated_by === null && rich) {
    return { safe: false, reason: 'manual_retro_null_inferred' };
  }
  if (retro.generated_by && !isAutoGenerated) {
    return { safe: false, reason: 'manual_retro' };
  }
  if (rich) {
    return { safe: false, reason: 'rich_existing_content' };
  }
  return { safe: true, reason: 'auto_thin' };
}

/**
 * Check whether it is safe to write a new retrospective for the given SD without
 * clobbering manually-curated content.
 *
 * Returns `{safe, reason, existingRetro}`. The `existingRetro` field is included so
 * callers can reuse the SELECT result instead of issuing a duplicate query (avoids
 * N+1 SELECT on the hot PLAN-TO-LEAD path).
 *
 * Dry-run mode: when `LEO_RETRO_GUARD_DRY_RUN=1`, the helper logs the would-skip
 * decision with `[DRY_RUN] would-have-skipped <reason>` prefix but always returns
 * `safe: true`. Enforce mode logs with `[ENFORCE] skipped <reason>` prefix at the
 * call site (not here — caller controls log timing).
 *
 * @param {Object} supabase - Supabase service-role client
 * @param {string} sdId - Strategic Directive UUID
 * @param {Object} [options] - Optional overrides for testing
 * @returns {Promise<{safe: boolean, reason: string, existingRetro: Object|null}>}
 */
export async function isSafeToWriteRetro(supabase, sdId, options = {}) {
  if (!supabase || !sdId) {
    return { safe: true, reason: 'no_supabase_or_sdid', existingRetro: null };
  }

  const { data: retro } = await supabase
    .from('retrospectives')
    .select('id, generated_by, auto_generated, key_learnings, status, retro_type, quality_score, created_at, updated_at, what_went_well, what_needs_improvement, action_items')
    .eq('sd_id', sdId)
    .order('created_at', { ascending: false })
    .limit(1)
    .maybeSingle();

  const decision = classifyRetro(retro);
  const dryRun = process.env.LEO_RETRO_GUARD_DRY_RUN === '1';

  if (!decision.safe && dryRun) {
    console.warn(`[DRY_RUN] would-have-skipped retro write for sdId=${sdId} reason=${decision.reason}`);
    return { safe: true, reason: `dry_run_override:${decision.reason}`, existingRetro: retro || null };
  }

  return { safe: decision.safe, reason: decision.reason, existingRetro: retro || null };
}
